  docs: {
    ...BrandColours.parameters?.docs,
    source: {
      originalSource: "{\n  name: 'Brand colour usage',\n  render: () => {\n    const icons = [PhosphorIcons.Compass, PhosphorIcons.Heart, PhosphorIcons.Bell, PhosphorIcons.Star] as Array<React.ComponentType<{\n      size: number;\n      weight: string;\n      color: string;\n    }>>;\n    const colors = [{\n      label: 'Active / brand/500',\n      color: '#186338'\n    }, {\n      label: 'Inactive / warm brown',\n      color: '#7D715E'\n    }, {\n      label: 'Muted / grey/400',\n      color: '#9AA0AD'\n    }, {\n      label: 'Error / error/500',\n      color: '#D64545'\n    }, {\n      label: 'White',\n      color: '#ffffff',\n      bg: '#186338'\n    }];\n    return <View style={{\n      padding: 20,\n      backgroundColor: '#F4F1EA',\n      gap: 20\n    }}>\n        {colors.map(({\n        label,\n        color,\n        bg\n      }) => <View key={label}>\n            <Text style={{\n          fontSize: 11,\n          color: '#9AA0AD',\n          fontFamily: 'Inter',\n          marginBottom: 10,\n          textTransform: 'uppercase',\n          letterSpacing: 0.5\n        }}>\n              {label} \xB7 {color}\n            </Text>\n            <View style={{\n          flexDirection: 'row',\n          gap: 20,\n          backgroundColor: bg,\n          padding: bg ? 12 : 0,\n          borderRadius: bg ? 12 : 0\n        }}>\n              {icons.map((Icon, i) => <Icon key={i} size={24} weight=\"regular\" color={color} />)}\n              {icons.map((Icon, i) => <Icon key={`fill-${i}`} size={24} weight=\"fill\" color={color} />)}\n            </View>\n          </View>)}\n      </View>;\n  }\n}",
      ...BrandColours.parameters?.docs?.source
    },
    description: {
      story: "How icons look with Sprout brand colours.",
      ...BrandColours.parameters?.docs?.description
    }
  }
